def get_labeling_pattern(examples):
    entity_types = get_entity_types(examples)
    patterns = []
    for example in examples:
        labels = example[-1]
        pattern = []
        for i, label in enumerate(labels):
            if label not in [O, 'O']:
                pattern.append(label)
            else:
                pattern.append('O')
        patterns.append(pattern)
    return patterns

def infer_labeling_pattern(patterns, query):
    # Create a dictionary to store the patterns
    pattern_dict = {}
    for i, pattern in enumerate(patterns):
        for j, label in enumerate(pattern):
            if label not in [O, 'O']:
                if label not in pattern_dict:
                    pattern_dict[label] = [j]
                else:
                    pattern_dict[label].append(j)

    # Create a list to store the inferred labeling pattern
    inferred_pattern = []
    for i, token in enumerate(query):
        if i in pattern_dict.get(O, []):
            inferred_pattern.append('O')
        else:
            for label in pattern_dict:
                if i in pattern_dict[label]:
                    inferred_pattern.append(label)
                    break
            else:
                inferred_pattern.append('O')

    return inferred_pattern

